patch:
--- a/comparator.v
+++ b/comparator.v
@@ -1,13 +1,13 @@
 module comparator_16bit (
   input [15:0] data_x,
   input [15:0] data_y,
   output equal_flag
 );
   assign equal_flag = (data_x == data_y);
 endmodule

 module top;
   wire [15:0] val1, val2;
   wire match;
-  comparator_16bit cmp1 (.data_x(val1[7:0]), .data_y(val2), .equal_flag(match));
+  comparator_16bit cmp1 (.data_x(val1), .data_y(val2), .equal_flag(match));
 endmodule

before_code:
module comparator_16bit (
  input [15:0] data_x,
  input [15:0] data_y,
  output equal_flag
);
  assign equal_flag = (data_x == data_y);
endmodule

module top;
  wire [15:0] val1, val2;
  wire match;
  comparator_16bit cmp1 (.data_x(val1[7:0]), .data_y(val2), .equal_flag(match));
endmodule

after_code:
module comparator_16bit (
  input [15:0] data_x,
  input [15:0] data_y,
  output equal_flag
);
  assign equal_flag = (data_x == data_y);
endmodule

module top;
  wire [15:0] val1, val2;
  wire match;
  comparator_16bit cmp1 (.data_x(val1), .data_y(val2), .equal_flag(match));
endmodule
